function generateKeyDescriptors(saml) {
  const authnSigned = saml["security.authnrequest_signed"] === "true";
  const wantEncrypted = saml["security.want_assertions_encrypted"] === "true";

  if (!authnSigned && !wantEncrypted) return "";

  const signingCert = saml["sp.privatekey"] || "sp-signing";
  const encCert = saml["sp.x509cert"] || "sp-encryption";

  // Same cert? → Single KeyDescriptor (no use)
  if (signingCert === encCert) {
    return `<md:KeyDescriptor>
      <ds:KeyInfo xmlns:ds="http://www.w3.org/2000/09/xmldsig#">
        <ds:X509Data>
          <ds:X509Certificate>REPLACE_WITH_${signingCert}_CERT</ds:X509Certificate>
        </ds:X509Data>
      </ds:KeyInfo>
    </md:KeyDescriptor>`;
  }

  // Different certs → Two KeyDescriptors
  let keys = "";
  if (authnSigned) {
    keys += `<md:KeyDescriptor use="signing">
      <ds:KeyInfo xmlns:ds="http://www.w3.org/2000/09/xmldsig#">
        <ds:X509Data>
          <ds:X509Certificate>REPLACE_WITH_${signingCert}_CERT</ds:X509Certificate>
        </ds:X509Data>
      </ds:KeyInfo>
    </md:KeyDescriptor>`;
  }
  if (wantEncrypted) {
    keys += `<md:KeyDescriptor use="encryption">
      <ds:KeyInfo xmlns:ds="http://www.w3.org/2000/09/xmldsig#">
        <ds:X509Data>
          <ds:X509Certificate>REPLACE_WITH_${encCert}_CERT</ds:X509Certificate>
        </ds:X509Data>
      </ds:KeyInfo>
    </md:KeyDescriptor>`;
  }
  return keys;
}

function generateSamlMetadataXml(jsonString) {
  const config = JSON.parse(jsonString);
  const saml = config.authentication.saml2;

  const entityId = saml["sp.entityid"];
  const nameIdFormat = saml["sp.nameidformat"];
  const acsUrl = saml["sp.assertion_consumer_service.url"];
  const authnSigned = saml["security.authnrequest_signed"] === "true";
  const wantAssertionsSigned =
    saml["security.want_assertions_signed"] === "true";
  const wantAssertionsEncrypted =
    saml["security.want_assertions_encrypted"] === "true";

  //  let keyDescriptors = '';
  let keyDescriptors = generateKeyDescriptors(saml);

  const xml = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<md:EntityDescriptor entityID="${entityId}"
  xmlns:md="urn:oasis:names:tc:SAML:2.0:metadata"
  xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
  xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
  xmlns:ds="http://www.w3.org/2000/09/xmldsig#">
  <md:SPSSODescriptor 
    AuthnRequestsSigned="${authnSigned}"
    WantAssertionsSigned="${wantAssertionsSigned}"
    protocolSupportEnumeration="urn:oasis:names:tc:SAML:2.0:protocol">
    ${keyDescriptors ? keyDescriptors + '\n    ' : ''}    
    <md:NameIDFormat>${nameIdFormat}</md:NameIDFormat>
    <md:AssertionConsumerService index="1" isDefault="true" 
      Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST" Location="${acsUrl}"/>
  </md:SPSSODescriptor>
</md:EntityDescriptor>`;

  return xml;
}

const jsonString = event.value.value;
const xmlOutput = generateSamlMetadataXml(jsonString);
stage.setValue(xmlOutput);
